import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PollenLevel {
  count: number;
  severity: string;
}

interface PollenTrend {
  day: string;
  count: number;
}

interface PollenData {
  location: string;
  currentPollenLevel: {
    tree: PollenLevel;
    grass: PollenLevel;
    weed: PollenLevel;
  };
  pollenTrend: PollenTrend[];
}

export default function Widget() {
  const { location, currentPollenLevel, pollenTrend } = response.data as PollenData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              Allergy Alert
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Location: {location}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Current Pollen Levels:
            </Typography>
            <Stack direction="row" spacing={1}>
              <Chip label={`Tree: ${currentPollenLevel.tree.severity}`} sx={{ bgcolor: '#FFCDD2', color: '#B71C1C' }} />
              <Chip label={`Grass: ${currentPollenLevel.grass.severity}`} sx={{ bgcolor: '#FFF9C4', color: '#F57F17' }} />
              <Chip label={`Weed: ${currentPollenLevel.weed.severity}`} sx={{ bgcolor: '#C8E6C9', color: '#388E3C' }} />
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: pollenTrend.map(t => t.count),
                  color: '#FF5722',
                  label: 'Pollen Count',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: pollenTrend.map(t => t.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'counts' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="counts"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
